sql:
SELECT COUNT(*) 
FROM employment_status 
WHERE is_active = 1;

-- Step 1: Identify active employment statuses
-- SELECT status_id FROM employment_status WHERE is_active = 1;

-- Step 2: Identify organizations with active employment statuses
-- SELECT DISTINCT org_id FROM employment_data WHERE status_id IN (SELECT status_id FROM employment_status WHERE is_active = 1);

-- Step 3: Find organizations without any active employment statuses
-- SELECT org_id FROM organizations WHERE org_id NOT IN (SELECT DISTINCT org_id FROM employment_data WHERE status_id IN (SELECT status_id FROM employment_status WHERE is_active = 1));

-- Step 4: Count the inactive organizations
SELECT COUNT(org_id) AS total_inactive_organizations
FROM organizations
WHERE org_id NOT IN (
    SELECT DISTINCT org_id
    FROM employment_data
    WHERE status_id IN (
        SELECT status_id
        FROM employment_status
        WHERE is_active = 1
    )
);

SELECT org_id, age_group_id
FROM employment_data
ORDER BY max_salary DESC;

external_knowledge:
- 'fruit-bearing trees' refers to employees who are currently holding active positions;
- 'nurturing' implies active management and support of the employees;
- 'four seasons' metaphorically represents the years from 2019 to 2022;
- 'fruit' symbolizes the employees themselves, and the 'count of fruit' represents the headcount;
- 'average sweetness of the harvest' is a metaphor for the mean salary.

sql:
SELECT AVG(mean_salary) 
FROM salary_trends 
WHERE age_group_id = 1 AND year = 2020;

external_knowledge:
- 'Soared highest in the financial skies' refers to the agencies with the highest mean salaries; 
- 'Age groups flew their flagship employees' denotes the age groups associated with the agencies and their employees; 
- 'Golden years of earning' metaphorically refers to the year 2020 for the given data context.
